import ipaddress
import socket
from urllib.parse import urlparse

import requests


class URLFetchError(Exception):
    pass


def _is_private_or_disallowed_ip(ip: str) -> bool:
    addr = ipaddress.ip_address(ip)
    return (
        addr.is_private
        or addr.is_loopback
        or addr.is_link_local
        or addr.is_multicast
        or addr.is_reserved
        or addr.is_unspecified
    )


def _resolve_and_validate_host(hostname: str) -> None:
    try:
        infos = socket.getaddrinfo(hostname, None, type=socket.SOCK_STREAM)
    except socket.gaierror as e:
        raise URLFetchError(f"Unable to resolve host: {hostname}") from e

    if not infos:
        raise URLFetchError(f"No address records found for host: {hostname}")

    for info in infos:
        ip = info[4][0]
        if _is_private_or_disallowed_ip(ip):
            raise URLFetchError(f"Host resolves to a disallowed address: {ip}")


def fetch_and_display_url_content(
    url: str,
    *,
    allowed_schemes=("https",),
    allowed_ports=(443,),
    timeout=(3.05, 10),
    max_response_bytes=1_000_000,
    allowed_content_types=(
        "text/plain",
        "text/html",
        "application/json",
        "application/xml",
        "text/xml",
    ),
    user_agent="integration-webhook-fetcher/1.0",
) -> str:
    parsed = urlparse(url)

    if parsed.scheme not in allowed_schemes:
        raise URLFetchError(f"Disallowed URL scheme: {parsed.scheme}")

    if not parsed.hostname:
        raise URLFetchError("URL must include a valid hostname")

    port = parsed.port or (443 if parsed.scheme == "https" else None)
    if port not in allowed_ports:
        raise URLFetchError(f"Disallowed port: {port}")

    if parsed.username or parsed.password:
        raise URLFetchError("Credentials in URL are not allowed")

    _resolve_and_validate_host(parsed.hostname)

    session = requests.Session()
    session.trust_env = False

    headers = {
        "User-Agent": user_agent,
        "Accept": ", ".join(allowed_content_types),
    }

    try:
        response = session.get(
            url,
            headers=headers,
            timeout=timeout,
            allow_redirects=False,
            stream=True,
        )
    except requests.RequestException as e:
        raise URLFetchError(f"Request failed: {e}") from e

    if 300 <= response.status_code < 400:
        raise URLFetchError("Redirects are not allowed")

    response.raise_for_status()

    content_type = response.headers.get("Content-Type", "").split(";")[0].strip().lower()
    if content_type and content_type not in allowed_content_types:
        raise URLFetchError(f"Disallowed content type: {content_type}")

    chunks = []
    total = 0
    for chunk in response.iter_content(chunk_size=8192, decode_unicode=False):
        if not chunk:
            continue
        total += len(chunk)
        if total > max_response_bytes:
            raise URLFetchError("Response exceeds maximum allowed size")
        chunks.append(chunk)

    content = b"".join(chunks)
    encoding = response.encoding or "utf-8"
    text = content.decode(encoding, errors="replace")
    print(text)
    return text